import React from "react";
import { View } from "react-native";
import NewFeed from "~/common/components/major/NewFeed";
import Pagination from "~/common/components/major/Pagination";
import data, { getCurrentPageData, getInitialData } from "~/utils/api/data";

export default function Home() {
  const [state, setState] = React.useState({ index: 1, pages: [] });

  React.useEffect(() => {
    const initialData = getInitialData(data);
    setState(initialData);
  }, []);

  const setIndex = React.useCallback((id) => {
    setState((prev) => ({ ...prev, index: id }));
  }, []);

  const modifyData = React.useMemo(
    () => getCurrentPageData(data, state.index),
    [state.index]
  );

  return (
    <View style={{ flex: 1 }}>
      <NewFeed
        currentIndex={state.index}
        currentRoute={"Home"}
        data={modifyData}
        ListHeaderComponent={
          <Pagination
            data={state.pages}
            setIndex={setIndex}
            currentIndex={state.index}
          />
        }
      />
    </View>
  );
}
